    public static final class SessionManager {
        private final String hmacSecret;
        private final long ttlSeconds;
        private final Map<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();

        public SessionManager(String hmacSecret, long ttlSeconds) {
            if (hmacSecret == null || hmacSecret.isBlank()) throw new IllegalArgumentException("hmacSecret required");
            this.hmacSecret = hmacSecret;
            this.ttlSeconds = Math.max(60, ttlSeconds);
        }

        public AuthenticatedSession createSession(SamlAuthentication auth) {
            Objects.requireNonNull(auth, "auth");
            long now = Instant.now().getEpochSecond();
            long expiresAt = now + ttlSeconds;

            if (auth.notOnOrAfterEpochSeconds() != Long.MAX_VALUE) {
                expiresAt = Math.min(expiresAt, auth.notOnOrAfterEpochSeconds());
            }
            if (expiresAt <= now) {
                throw new SamlValidationException("Cannot create session: assertion expired");
            }

            String payload = auth.subjectNameId() + "|" + nullToEmpty(auth.issuer()) + "|" + now + "|" + expiresAt + "|" + nullToEmpty(auth.sessionIndex());
            String sig = hmacSha256Base64Url(hmacSecret, payload);
            String sessionId = base64Url(payload.getBytes(StandardCharsets.UTF_8)) + "." + sig;

            AuthenticatedSession session = new AuthenticatedSession(
                    sessionId,
                    auth.subjectNameId(),
                    auth.issuer(),
                    auth.attributes(),
                    now,
                    expiresAt,
                    auth.sessionIndex(),
                    auth.responseId(),
                    auth.assertionId()
            );
            sessions.put(sessionId, session);
            return session;
        }

        public Optional<AuthenticatedSession> getSession(String sessionId) {
            if (sessionId == null || sessionId.isBlank()) return Optional.empty();
            AuthenticatedSession s = sessions.get(sessionId);
            if (s == null) return Optional.empty();
            long now = Instant.now().getEpochSecond();
            if (now >= s.expiresAtEpochSeconds()) {
                sessions.remove(sessionId);
                return Optional.empty();
            }
            if (!verifySessionId(sessionId)) {
                sessions.remove(sessionId);
                return Optional.empty();
            }
            return Optional.of(s);
        }

        public void invalidate(String sessionId) {
            if (sessionId == null) return;
            sessions.remove(sessionId);
        }

        private boolean verifySessionId(String sessionId) {
            int dot = sessionId.lastIndexOf('.');
            if (dot <= 0 || dot == sessionId.length() - 1) return false;
            String payloadB64 = sessionId.substring(0, dot);
            String sig = sessionId.substring(dot + 1);
            String payload;
            try {
                payload = new String(Base64.getUrlDecoder().decode(payloadB64), StandardCharsets.UTF_8);
            } catch (Exception e) {
                return false;
            }
            String expectedSig = hmacSha256Base64Url(hmacSecret, payload);
            return constantTimeEquals(sig, expectedSig);
        }

        private static String nullToEmpty(String s) { return s == null ? "" : s; }

        private static String hmacSha256Base64Url(String secret, String data) {
            try {
                Mac mac = Mac.getInstance("HmacSHA256");
                mac.init(new SecretKeySpec(secret.getBytes(StandardCharsets.UTF_8), "HmacSHA256"));
                byte[] out = mac.doFinal(data.getBytes(StandardCharsets.UTF_8));
                return base64Url(out);
            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        }

        private static String base64Url(byte[] bytes) {
            return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        }

        private static boolean constantTimeEquals(String a, String b) {
            if (a == null || b == null) return false;
            byte[] x = a.getBytes(StandardCharsets.UTF_8);
            byte[] y = b.getBytes(StandardCharsets.UTF_8);
            return MessageDigest.isEqual(x, y);
        }
    }

